__kernel void dynproc_kernel(
    int pyramid_height,
    __global const int* wall,
    __global const int* src,
    __global int* dst,
    int cols,
    int rows,
    int t_offset,
    int borderCols,
    int halo,
    __local int* local_buf1,
    __local int* local_buf2,
    __global int* outputBuffer)
{
    int col = get_global_id(0);

    if (col >= cols) return;

    // Initial values from src buffer
    int current = src[col];
    int left = (col > 0) ? src[col-1] : current;
    int right = (col < cols-1) ? src[col+1] : current;

    // Process pyramid_height rows
    for (int h = 0; h < pyramid_height; h++) {
        // Check if we've exceeded the grid
        if (t_offset + h + 1 >= rows) break;

        // Find minimum of current position and neighbors
        int min_val = current;
        if (left < min_val) min_val = left;
        if (right < min_val) min_val = right;

        // Compute new value: wall value + minimum path
        int wall_idx = (t_offset + h) * cols + col;
        current = wall[wall_idx] + min_val;

        // Write result to destination buffer
        dst[col] = current;

        // Update neighbor values for next iteration
        if (h + 1 < pyramid_height) {
            if (col > 0) left = dst[col-1];
            if (col < cols-1) right = dst[col+1];
        }
    }
}
